mapper.select:
SELECT id, user_id, title, description, category, status, priority, due_date, progress, created_at, updated_at
FROM plans
WHERE user_id = #{userId}

    AND status = #{status}


    AND category = #{category}


    AND (title LIKE CONCAT('%', #{keyword}, '%') OR description LIKE CONCAT('%', #{keyword}, '%'))

ORDER BY updated_at DESC, id DESC
